318→const createInitialMediaCursorState = () => ({
319→    offsets: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, 0])),
320→    exhausted: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, false])),
321→    pending: []
322→});
323→
324→const parseMediaCursor = (cursor) => {
325→    if(!cursor){
326→        return createInitialMediaCursorState();
327→    }
328→
329→    try {
330→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
331→        const parsed = JSON.parse(decoded);
332→        const initial = createInitialMediaCursorState();
333→
334→        if(parsed?.offsets && typeof parsed.offsets === 'object'){
335→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
336→                const value = Number(parsed.offsets[bucket]);
337→                initial.offsets[bucket] = Number.isNaN(value) || value < 0 ? 0 : value;
338→            });
339→        }
340→
341→        if(parsed?.exhausted && typeof parsed.exhausted === 'object'){
342→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
343→                initial.exhausted[bucket] = Boolean(parsed.exhausted[bucket]);
344→            });
345→        }
346→
347→        if(Array.isArray(parsed?.pending)){
348→            initial.pending = parsed.pending
349→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
350→                .map((item) => ({
351→                    bucket: item.bucket,
352→                    path: item.path,
353→                    name: item.name,
354→                    createdAt: item.createdAt || null,
355→                    timestamp: Number(item.timestamp) || 0
356→                }));
357→        }
358→
359→        return initial;
360→    } catch {
361→        return createInitialMediaCursorState();
362→    }
363→};
